INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('87451b14-bce1-4321-8758-020652a938db', '6fa1a44e-a289-11e7-8d59-02d2a924e5ba', '区域外时间不能小于今天', 'tot_date>now', 'trigger', 'from django.utils.timezone import utc, localtime\nfrom django.utils import timezone\nimport datetime\nif instance:\n    if instance.date:\n        edit_time = datetime.datetime.strptime(instance.date, \'%Y-%m-%d\').date()\n        now_date_str = timezone.localtime(timezone.now()).strftime(\'%Y-%m-%d\')\n        now_date = datetime.datetime.strptime(now_date_str, \'%Y-%m-%d\').date()\n        if edit_time < now_date:\n            message = u\'不允许创建过往的区域外时间\'\n            raise create_validation_trigger_rule_errors(message)\n', '', '0', '1', '2020-08-19 11:08:42', '1', '2020-10-17 09:39:34', 'pre_save', '1', 'custom', 'tot_date_validation', '1');
