INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('b7544a84-6b03-488d-9874-f9bcfdd118ic', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '会议保存时将讲者插入参会人', '会议保存时将讲者插入参会人', 'trigger', 'from orionbase.common import models\nif instance and instance.id:\n    event_speakers = models.EventSpeakers.objects.filter(event_id=instance.id,deleted=0)\n    models.EventAccounts.objects.filter(event_id=instance.id,boolean_1 = 1).delete()\n    for event_speaker in event_speakers:\n        speaker = models.Speakers.objects.filter(id=event_speaker.speaker_id,deleted=0).first()\n        if speaker:\n            # 避免参会人和讲者都被选择了同一人\n            models.EventAccounts.objects.filter(event_id=instance.id,account_id=speaker.professional_id).delete()\n            speaker_account = models.EventAccounts(\n                                created_on = event_speaker.created_on,\n                                modified_on = event_speaker.modified_on,\n                                created_by = event_speaker.created_by,\n                                modified_by = event_speaker.modified_by,\n                                deleted = event_speaker.deleted,\n                                account_id = speaker.professional_id,\n                                event_id =  event_speaker.event_id,\n                                owner =  event_speaker.owner,\n                                record_type_id =\'c1491afa-18f4-4046-8e25-b62aed90eb77\',\n                                boolean_1 = 1\n                            )\n            speaker_account.save()', '', '0', '1', '2020-10-17 06:45:37', '1', '2020-10-17 12:51:15', 'post_save_page', '1', 'custom', 'cs_event_speaker_to_eventaccount', '1');
