-- trigger tot时间>=now
-- 城市级讲者在科室会，病人教育会内讲课，单次不超过1300
UPDATE `object_validations` SET `trigger_code` = '# object_name = sender._meta.db_table\n# if object_name == \'event_speakers\' and event == \'pre_save\':\nmsg = \'\'\n# 1. 单会议的讲者使用限制\n# 讲者级别	单次费用限制（含）	全年单一讲者讲课费支付上限	年度使用次数	特殊规则\n# 城市级	1300~3200	<=120000	<25次	城市级讲者在科室会内讲课，单次不超过1300\n# 区域级	2500~5000	<=150000	<25次\n# 全国级	3800~7500	<=200000	<25次\n\nif instance.speaker_level.label == u\'城市级\':\n    if instance.speaker_expense > 3200:\n        msg += u\'城市级讲者（%s）单次费用限制0~3200\' % instance.speaker.name\n    # 科室会的特殊规则\n    if instance.event.record_type.name in (\'cs_department\',\'cs_department__report\',\'cs_patient_education_meeting\',\'cs_patient_education_meeting__report\'):\n        if instance.speaker_expense > 1300:\n            msg += u\'城市级讲者（%s）在学术推广会议-科室会/院内会、病人教育会内讲课，单次不超过1300\' % instance.speaker.name\nif instance.speaker_level.label == u\'区域级\':\n    if instance.speaker_expense > 5000:\n        msg += u\'区域级讲者（%s）单次费用限制0~5000\' % instance.speaker.name\nif instance.speaker_level.label == u\'全国级\':\n    if instance.speaker_expense > 7500:\n        msg += u\'全国级讲者（%s）单次费用限制0~7500\' % instance.speaker.name\nif msg:\n    raise create_validation_trigger_rule_errors(msg)' WHERE (`id` = '87451b14-bce1-1234-8758-020652a9390e');
-- 添加会议产品，放在会议时间后面 order =7

update page_layout_fields set `order`=`order`+1 where deleted=0 and `order`>=11 and  page_layout_id in 
(select page_layout_id from page_layout_assignments where deleted=0 and  object_record_type_id in 
(select id from object_record_types where object_id='3f49c30f-5d59-11e6-a130-5cc5d4d378cb' and  deleted=0)
and object_state_id in (select id from object_states where object_id='3f49c30f-5d59-11e6-a130-5cc5d4d378cb' and deleted=0));


update page_layout_fields a,
(select * from page_layout_fields where object_field_id = 'eee173de-a59d-dsac-b11b-5cc5d4d378cb' and deleted=0 and label='外部讲者') as b
set a.is_readonly = b.is_readonly where a.page_layout_id=b.page_layout_id
and a.object_field_id='a848e630-6b59-11e6-9673-5cc5d4d378cb' and a.deleted=0 and a.created_on like '2020-10-17%';

